    window.clearTimeout(stableConnectionTimerRef.current);
    stableConnectionTimerRef.current = undefined;
  }, []);

  const markTerminalConnectionUseful = useCallback(() => {
    clearStableConnectionTimer();
    reconnectAttemptRef.current = 0;
  }, [clearStableConnectionTimer]);

  const markTerminalConnectionStableLater = useCallback(() => {
    clearStableConnectionTimer();
    stableConnectionTimerRef.current = window.setTimeout(() => {
      stableConnectionTimerRef.current = undefined;
      reconnectAttemptRef.current = 0;
    }, terminalStableConnectionMs);
  }, [clearStableConnectionTimer]);

  const scheduleTerminalReconnect = useCallback(() => {
    if (!sessionId || !sessionProject || !sessionTerminalSupported) {
      return;
    }

    if (reconnectTimerRef.current !== undefined) {
      return;
    }

    const nextDelay = terminalReconnectDelaysMs[reconnectAttemptRef.current];
    if (nextDelay === undefined) {
      return;
    }

    reconnectAttemptRef.current += 1;
    reconnectTimerRef.current = window.setTimeout(() => {
      reconnectTimerRef.current = undefined;
      clearBeforeNextMessageRef.current = true;
      setConnectionAttempt((currentAttempt) => currentAttempt + 1);
    }, nextDelay);
  }, [sessionId, sessionProject, sessionTerminalSupported]);

